     3вҶ’// ============================================================================
     4вҶ’
     5вҶ’use std::collections::HashMap;
     6вҶ’use std::fmt;
     7вҶ’
     8вҶ’/// лҹ°нғҖмһ„ к°’
     9вҶ’#[derive(Debug, Clone, PartialEq)]
    10вҶ’pub enum Value {
    11вҶ’    /// м •мҲҳ
    12вҶ’    Int(i64),
    13вҶ’
    14вҶ’    /// л¶ҲлҰ¬м–ё
    15вҶ’    Bool(bool),
    16вҶ’
    17вҶ’    /// null
    18вҶ’    Null,
    19вҶ’
    20вҶ’    /// л°°м—ҙ
    21вҶ’    Array(Vec<Value>),
    22вҶ’
    23вҶ’    /// н•ҙмӢңл§ө
    24вҶ’    HashMap(HashMap<String, Value>),
    25вҶ’}
    26вҶ’
    27вҶ’impl Value {
    28вҶ’    /// к°’мқҙ м°ёмқём§Җ нҢҗлӢЁ
    29вҶ’    pub fn is_truthy(&self) -> bool {
    30вҶ’        match self {
    31вҶ’            Value::Bool(b) => *b,
    32вҶ’            Value::Int(0) => false,
    33вҶ’            Value::Int(_) => true,
    34вҶ’            Value::Null => false,
    35вҶ’            Value::Array(_) => true,
    36вҶ’            Value::HashMap(_) => true,
    37вҶ’        }
    38вҶ’    }
    39вҶ’}
    40вҶ’
    41вҶ’impl fmt::Display for Value {
    42вҶ’    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    43вҶ’        match self {
    44вҶ’            Value::Int(n) => write!(f, "{}", n),
    45вҶ’            Value::Bool(b) => write!(f, "{}", b),
    46вҶ’            Value::Null => write!(f, "null"),
    47вҶ’            Value::Array(arr) => {
    48вҶ’                write!(f, "[")?;
    49вҶ’                for (i, v) in arr.iter().enumerate() {
    50вҶ’                    if i > 0 {
    51вҶ’                        write!(f, ", ")?;
    52вҶ’                    }
    53вҶ’                    write!(f, "{}", v)?;
    54вҶ’                }
    55вҶ’                write!(f, "]")
    56вҶ’            }
    57вҶ’            Value::HashMap(map) => {
    58вҶ’                write!(f, "{{")?;
    59вҶ’                let mut first = true;
    60вҶ’                for (k, v) in map.iter() {
    61вҶ’                    if !first {
    62вҶ’                        write!(f, ", ")?;
    63вҶ’                    }
    64вҶ’                    write!(f, "{}: {}", k, v)?;
    65вҶ’                    first = false;
    66вҶ’                }
    67вҶ’                write!(f, "}}")
    68вҶ’            }
    69вҶ’        }
    70вҶ’    }
    71вҶ’}
    72вҶ’
    73вҶ’#[cfg(test)]
    74вҶ’mod tests {
    75вҶ’    use super::*;
    76вҶ’
    77вҶ’    #[test]
    78вҶ’    fn test_is_truthy_bool() {
    79вҶ’        assert!(Value::Bool(true).is_truthy());
    80вҶ’        assert!(!Value::Bool(false).is_truthy());
    81вҶ’    }
    82вҶ’
    83вҶ’    #[test]
    84вҶ’    fn test_is_truthy_int() {
    85вҶ’        assert!(!Value::Int(0).is_truthy());
    86вҶ’        assert!(Value::Int(1).is_truthy());
    87вҶ’        assert!(Value::Int(-1).is_truthy());
    88вҶ’    }
    89вҶ’
    90вҶ’    #[test]
    91вҶ’    fn test_is_truthy_null() {
    92вҶ’        assert!(!Value::Null.is_truthy());
    93вҶ’    }
    94вҶ’
    95вҶ’    #[test]
    96вҶ’    fn test_is_truthy_array() {
    97вҶ’        assert!(Value::Array(vec![]).is_truthy());
    98вҶ’        assert!(Value::Array(vec![Value::Int(1)]).is_truthy());
    99вҶ’    }
   100вҶ’
   101вҶ’    #[test]
   102вҶ’    fn test_display() {
   103вҶ’        assert_eq!(Value::Int(42).to_string(), "42");
   104вҶ’        assert_eq!(Value::Bool(true).to_string(), "true");
   105вҶ’        assert_eq!(Value::Null.to_string(), "null");
   106вҶ’        assert_eq!(
   107вҶ’            Value::Array(vec![Value::Int(1), Value::Int(2)]).to_string(),
   108вҶ’            "[1, 2]"
   109вҶ’        );
   110вҶ’    }
   111вҶ’}
