     2вҶ’// VM: Virtual Machine - л°”мқҙнҠёмҪ”л“ң мӢӨн–ү м—”м§„
     3вҶ’// ============================================================================
     4вҶ’
     5вҶ’use crate::bytecode::Bytecode;
     6вҶ’use crate::opcode::OpCode;
     7вҶ’use crate::value::Value;
     8вҶ’use std::collections::HashMap;
     9вҶ’
    10вҶ’/// к°ҖмғҒ лЁёмӢ 
    11вҶ’pub struct VM {
    12вҶ’    bytecode: Bytecode,
    13вҶ’    stack: Vec<Value>,
    14вҶ’    ip: usize, // Instruction Pointer
    15вҶ’}
    16вҶ’
    17вҶ’impl VM {
    18вҶ’    /// мғҲлЎңмҡҙ VM мғқм„ұ
    19вҶ’    pub fn new(bytecode: Bytecode) -> Self {
    20вҶ’        VM {
    21вҶ’            bytecode,
    22вҶ’            stack: Vec::with_capacity(256),
    23вҶ’            ip: 0,
    24вҶ’        }
    25вҶ’    }
    26вҶ’
    27вҶ’    /// л°”мқҙнҠёмҪ”л“ң мӢӨн–ү
    28вҶ’    pub fn run(&mut self) -> Result<Value, String> {
    29вҶ’        while self.ip < self.bytecode.instructions.len() {
    30вҶ’            let op_byte = self.bytecode.instructions[self.ip];
    31вҶ’            self.ip += 1;
    32вҶ’
    33вҶ’            let op = OpCode::from_byte(op_byte).ok_or(format!("Unknown opcode: {}", op_byte))?;
    34вҶ’
    35вҶ’            match op {
    36вҶ’                OpCode::OpConstant => {
    37вҶ’                    let idx = self.read_u16() as usize;
    38вҶ’                    let val = self
    39вҶ’                        .bytecode
    40вҶ’                        .get_constant(idx)
    41вҶ’                        .ok_or(format!("Constant index out of bounds: {}", idx))?;
    42вҶ’                    self.stack.push(Value::Int(val));
    43вҶ’                }
    44вҶ’
    45вҶ’                OpCode::OpAdd => {
    46вҶ’                    let right = self.stack_pop()?;
    47вҶ’                    let left = self.stack_pop()?;
    48вҶ’                    match (left, right) {
    49вҶ’                        (Value::Int(l), Value::Int(r)) => {
    50вҶ’                            self.stack.push(Value::Int(l + r));
    51вҶ’                        }
    52вҶ’                        _ => return Err("Cannot add non-integers".to_string()),
    53вҶ’                    }
    54вҶ’                }
    55вҶ’
    56вҶ’                OpCode::OpSub => {
    57вҶ’                    let right = self.stack_pop()?;
    58вҶ’                    let left = self.stack_pop()?;
    59вҶ’                    match (left, right) {
    60вҶ’                        (Value::Int(l), Value::Int(r)) => {
    61вҶ’                            self.stack.push(Value::Int(l - r));
    62вҶ’                        }
    63вҶ’                        _ => return Err("Cannot subtract non-integers".to_string()),
    64вҶ’                    }
    65вҶ’                }
    66вҶ’
    67вҶ’                OpCode::OpMul => {
    68вҶ’                    let right = self.stack_pop()?;
    69вҶ’                    let left = self.stack_pop()?;
    70вҶ’                    match (left, right) {
    71вҶ’                        (Value::Int(l), Value::Int(r)) => {
    72вҶ’                            self.stack.push(Value::Int(l * r));
    73вҶ’                        }
    74вҶ’                        _ => return Err("Cannot multiply non-integers".to_string()),
    75вҶ’                    }
    76вҶ’                }
    77вҶ’
    78вҶ’                OpCode::OpDiv => {
    79вҶ’                    let right = self.stack_pop()?;
    80вҶ’                    let left = self.stack_pop()?;
    81вҶ’                    match (left, right) {
    82вҶ’                        (Value::Int(l), Value::Int(r)) => {
    83вҶ’                            if r == 0 {
    84вҶ’                                return Err("Division by zero".to_string());
    85вҶ’                            }
    86вҶ’                            self.stack.push(Value::Int(l / r));
    87вҶ’                        }
    88вҶ’                        _ => return Err("Cannot divide non-integers".to_string()),
    89вҶ’                    }
    90вҶ’                }
    91вҶ’
    92вҶ’                OpCode::OpTrue => {
    93вҶ’                    self.stack.push(Value::Bool(true));
    94вҶ’                }
    95вҶ’
    96вҶ’                OpCode::OpFalse => {
    97вҶ’                    self.stack.push(Value::Bool(false));
    98вҶ’                }
    99вҶ’
   100вҶ’                OpCode::OpEqual => {
   101вҶ’                    let right = self.stack_pop()?;
   102вҶ’                    let left = self.stack_pop()?;
   103вҶ’                    self.stack.push(Value::Bool(left == right));
   104вҶ’                }
   105вҶ’
   106вҶ’                OpCode::OpNotEqual => {
   107вҶ’                    let right = self.stack_pop()?;
   108вҶ’                    let left = self.stack_pop()?;
   109вҶ’                    self.stack.push(Value::Bool(left != right));
   110вҶ’                }
   111вҶ’
   112вҶ’                OpCode::OpLessThan => {
   113вҶ’                    let right = self.stack_pop()?;
   114вҶ’                    let left = self.stack_pop()?;
   115вҶ’                    match (left, right) {
   116вҶ’                        (Value::Int(l), Value::Int(r)) => {
   117вҶ’                            self.stack.push(Value::Bool(l < r));
   118вҶ’                        }
   119вҶ’                        _ => return Err("Cannot compare non-integers".to_string()),
   120вҶ’                    }
   121вҶ’                }
   122вҶ’
   123вҶ’                OpCode::OpGreaterThanOrEqual => {
   124вҶ’                    let right = self.stack_pop()?;
   125вҶ’                    let left = self.stack_pop()?;
   126вҶ’                    match (left, right) {
   127вҶ’                        (Value::Int(l), Value::Int(r)) => {
   128вҶ’                            self.stack.push(Value::Bool(l >= r));
   129вҶ’                        }
   130вҶ’                        _ => return Err("Cannot compare non-integers".to_string()),
   131вҶ’                    }
   132вҶ’                }
   133вҶ’
   134вҶ’                OpCode::OpBang => {
   135вҶ’                    let val = self.stack_pop()?;
   136вҶ’                    self.stack.push(Value::Bool(!val.is_truthy()));
   137вҶ’                }
   138вҶ’
   139вҶ’                OpCode::OpMinus => {
   140вҶ’                    let val = self.stack_pop()?;
   141вҶ’                    match val {
   142вҶ’                        Value::Int(n) => self.stack.push(Value::Int(-n)),
   143вҶ’                        _ => return Err("Cannot negate non-integer".to_string()),
   144вҶ’                    }
   145вҶ’                }
   146вҶ’
   147вҶ’                OpCode::OpJump => {
   148вҶ’                    let target = self.read_u16() as usize;
   149вҶ’                    self.ip = target;
   150вҶ’                }
   151вҶ’
   152вҶ’                OpCode::OpJumpNotTruthy => {
   153вҶ’                    let target = self.read_u16() as usize;
   154вҶ’                    let cond = self.stack_pop()?;
   155вҶ’                    if !cond.is_truthy() {
   156вҶ’                        self.ip = target;
   157вҶ’                    }
   158вҶ’                }
   159вҶ’
   160вҶ’                OpCode::OpNull => {
   161вҶ’                    self.stack.push(Value::Null);
   162вҶ’                }
   163вҶ’
   164вҶ’                OpCode::OpPop => {
   165вҶ’                    let _ = self.stack_pop()?;
   166вҶ’                }
   167вҶ’
   168вҶ’                OpCode::OpArray => {
   169вҶ’                    let count = self.read_u16() as usize;
   170вҶ’                    let mut arr = Vec::with_capacity(count);
   171вҶ’                    for _ in 0..count {
   172вҶ’                        arr.push(self.stack_pop()?);
   173вҶ’                    }
   174вҶ’                    arr.reverse();
   175вҶ’                    self.stack.push(Value::Array(arr));
   176вҶ’                }
   177вҶ’
   178вҶ’                OpCode::OpHash => {
   179вҶ’                    let count = self.read_u16() as usize;
   180вҶ’                    let mut map = HashMap::new();
   181вҶ’                    for _ in 0..count {
   182вҶ’                        let val = self.stack_pop()?;
   183вҶ’                        let key = match self.stack_pop()? {
   184вҶ’                            Value::Int(n) => n.to_string(),
   185вҶ’                            _ => return Err("Hash keys must be integers".to_string()),
   186вҶ’                        };
   187вҶ’                        map.insert(key, val);
   188вҶ’                    }
   189вҶ’                    self.stack.push(Value::HashMap(map));
   190вҶ’                }
   191вҶ’
   192вҶ’                OpCode::OpIndex => {
   193вҶ’                    let idx = self.stack_pop()?;
   194вҶ’                    let arr = self.stack_pop()?;
   195вҶ’
   196вҶ’                    match (arr, idx) {
   197вҶ’                        (Value::Array(arr), Value::Int(i)) => {
   198вҶ’                            let idx = if i < 0 {
   199вҶ’                                (arr.len() as i64 + i) as usize
   200вҶ’                            } else {
   201вҶ’                                i as usize
   202вҶ’                            };
   203вҶ’
   204вҶ’                            if idx < arr.len() {
   205вҶ’                                self.stack.push(arr[idx].clone());
   206вҶ’                            } else {
   207вҶ’                                self.stack.push(Value::Null);
   208вҶ’                            }
   209вҶ’                        }
   210вҶ’                        (Value::HashMap(map), key_val) => {
   211вҶ’                            let key = match key_val {
   212вҶ’                                Value::Int(n) => n.to_string(),
   213вҶ’                                _ => return Err("Hash keys must be integers".to_string()),
   214вҶ’                            };
   215вҶ’                            match map.get(&key) {
   216вҶ’                                Some(val) => self.stack.push(val.clone()),
   217вҶ’                                None => self.stack.push(Value::Null),
   218вҶ’                            }
   219вҶ’                        }
   220вҶ’                        _ => return Err("Invalid indexing operation".to_string()),
   221вҶ’                    }
   222вҶ’                }
   223вҶ’
   224вҶ’                OpCode::OpReturnValue | OpCode::OpReturn => {
   225вҶ’                    if let OpCode::OpReturnValue = op {
   226вҶ’                        return self.stack_pop();
   227вҶ’                    } else {
   228вҶ’                        return Ok(Value::Null);
   229вҶ’                    }
   230вҶ’                }
   231вҶ’
   232вҶ’                OpCode::OpEnd => {
   233вҶ’                    break;
   234вҶ’                }
   235вҶ’
   236вҶ’                _ => return Err(format!("Unimplemented opcode: {:?}", op)),
   237вҶ’            }
   238вҶ’        }
   239вҶ’
   240вҶ’        // мҠӨнғқм—җ к°’мқҙ лӮЁм•„мһҲмңјл©ҙ л°ҳнҷҳ
   241вҶ’        if !self.stack.is_empty() {
   242вҶ’            self.stack_pop()
   243вҶ’        } else {
   244вҶ’            Ok(Value::Null)
   245вҶ’        }
   246вҶ’    }
   247вҶ’
   248вҶ’    /// мҠӨнғқм—җм„ң 2л°”мқҙнҠё мқҪкё° (Big-Endian)
   249вҶ’    fn read_u16(&mut self) -> u16 {
   250вҶ’        let high = self.bytecode.instructions[self.ip] as u16;
   251вҶ’        let low = self.bytecode.instructions[self.ip + 1] as u16;
   252вҶ’        self.ip += 2;
   253вҶ’        (high << 8) | low
   254вҶ’    }
   255вҶ’
   256вҶ’    /// мҠӨнғқм—җм„ң к°’ нҢқ
   257вҶ’    fn stack_pop(&mut self) -> Result<Value, String> {
   258вҶ’        self.stack.pop().ok_or_else(|| "Stack underflow".to_string())
   259вҶ’    }
   260вҶ’
   261вҶ’    /// мҠӨнғқмқҳ мөңмғҒлӢЁ к°’ мЎ°нҡҢ (нҢқн•ҳм§Җ м•ҠмқҢ)
   262вҶ’    pub fn stack_peek(&self) -> Option<&Value> {
   263вҶ’        self.stack.last()
   264вҶ’    }
   265вҶ’
   266вҶ’    /// мҠӨнғқ мғҒнғң нҷ•мқё
   267вҶ’    pub fn stack(&self) -> &[Value] {
   268вҶ’        &self.stack
   269вҶ’    }
   270вҶ’}
   271вҶ’
   272вҶ’#[cfg(test)]
   273вҶ’mod tests {
   274вҶ’    use super::*;
   275вҶ’
   276вҶ’    #[test]
   277вҶ’    fn test_constant_integer() {
   278вҶ’        let mut bytecode = Bytecode::new();
   279вҶ’        let idx = bytecode.add_constant(42);
   280вҶ’        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   281вҶ’        bytecode.add_instruction((idx >> 8) as u8);
   282вҶ’        bytecode.add_instruction((idx & 0xFF) as u8);
   283вҶ’
   284вҶ’        let mut vm = VM::new(bytecode);
   285вҶ’        let result = vm.run().unwrap();
   286вҶ’
   287вҶ’        assert_eq!(result, Value::Int(42));
   288вҶ’    }
   289вҶ’
   290вҶ’    #[test]
   291вҶ’    fn test_arithmetic() {
   292вҶ’        let mut bytecode = Bytecode::new();
   293вҶ’        let idx5 = bytecode.add_constant(5);
   294вҶ’        let idx3 = bytecode.add_constant(3);
   295вҶ’
   296вҶ’        // PUSH 5
   297вҶ’        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   298вҶ’        bytecode.add_instruction((idx5 >> 8) as u8);
   299вҶ’        bytecode.add_instruction((idx5 & 0xFF) as u8);
   300вҶ’
   301вҶ’        // PUSH 3
   302вҶ’        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   303вҶ’        bytecode.add_instruction((idx3 >> 8) as u8);
   304вҶ’        bytecode.add_instruction((idx3 & 0xFF) as u8);
   305вҶ’
   306вҶ’        // ADD
   307вҶ’        bytecode.add_instruction(OpCode::OpAdd.as_byte());
   308вҶ’
   309вҶ’        let mut vm = VM::new(bytecode);
   310вҶ’        let result = vm.run().unwrap();
   311вҶ’
   312вҶ’        assert_eq!(result, Value::Int(8));
   313вҶ’    }
   314вҶ’
   315вҶ’    #[test]
   316вҶ’    fn test_boolean() {
   317вҶ’        let mut bytecode = Bytecode::new();
   318вҶ’        bytecode.add_instruction(OpCode::OpTrue.as_byte());
   319вҶ’
   320вҶ’        let mut vm = VM::new(bytecode);
   321вҶ’        let result = vm.run().unwrap();
   322вҶ’
   323вҶ’        assert_eq!(result, Value::Bool(true));
   324вҶ’    }
   325вҶ’
   326вҶ’    #[test]
   327вҶ’    fn test_array() {
   328вҶ’        let mut bytecode = Bytecode::new();
   329вҶ’        let idx1 = bytecode.add_constant(1);
   330вҶ’        let idx2 = bytecode.add_constant(2);
   331вҶ’        let idx3 = bytecode.add_constant(3);
   332вҶ’
   333вҶ’        // PUSH 1
   334вҶ’        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   335вҶ’        bytecode.add_instruction((idx1 >> 8) as u8);
   336вҶ’        bytecode.add_instruction((idx1 & 0xFF) as u8);
   337вҶ’
   338вҶ’        // PUSH 2
   339вҶ’        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   340вҶ’        bytecode.add_instruction((idx2 >> 8) as u8);
   341вҶ’        bytecode.add_instruction((idx2 & 0xFF) as u8);
   342вҶ’
   343вҶ’        // PUSH 3
   344вҶ’        bytecode.add_instruction(OpCode::OpConstant.as_byte());
   345вҶ’        bytecode.add_instruction((idx3 >> 8) as u8);
   346вҶ’        bytecode.add_instruction((idx3 & 0xFF) as u8);
   347вҶ’
   348вҶ’        // ARRAY 3
   349вҶ’        bytecode.add_instruction(OpCode::OpArray.as_byte());
   350вҶ’        bytecode.add_instruction(0);
   351вҶ’        bytecode.add_instruction(3);
   352вҶ’
   353вҶ’        let mut vm = VM::new(bytecode);
   354вҶ’        let result = vm.run().unwrap();
   355вҶ’
   356вҶ’        assert_eq!(
   357вҶ’            result,
   358вҶ’            Value::Array(vec![Value::Int(1), Value::Int(2), Value::Int(3)])
   359вҶ’        );
   360вҶ’    }
   361вҶ’
   362вҶ’    #[test]
   363вҶ’    fn test_is_truthy() {
   364вҶ’        assert!(Value::Bool(true).is_truthy());
   365вҶ’        assert!(!Value::Bool(false).is_truthy());
   366вҶ’        assert!(Value::Int(1).is_truthy());
   367вҶ’        assert!(!Value::Int(0).is_truthy());
   368вҶ’    }
   369вҶ’}
