     2вҶ’// Compiler: ASTлҘј л°”мқҙнҠёмҪ”л“ңлЎң ліҖнҷҳ (v15.2 - л°ұн•„л§Ғ мҷ„м„ұ)
     3вҶ’// ============================================================================
     4вҶ’
     5вҶ’use crate::ast::{Expression, Program, Statement};
     6вҶ’use crate::bytecode::Bytecode;
     7вҶ’use crate::opcode::OpCode;
     8вҶ’
     9вҶ’/// ============================================================================
    10вҶ’/// м»ҙнҢҢмқјлҹ¬ - AST вҶ’ л°”мқҙнҠёмҪ”л“ң ліҖнҷҳмқҳ н•өмӢ¬
    11вҶ’/// ============================================================================
    12вҶ’pub struct Compiler {
    13вҶ’    bytecode: Bytecode,
    14вҶ’    pub debug_mode: bool,
    15вҶ’}
    16вҶ’
    17вҶ’impl Compiler {
    18вҶ’    /// мғҲлЎңмҡҙ м»ҙнҢҢмқјлҹ¬ мғқм„ұ
    19вҶ’    pub fn new() -> Self {
    20вҶ’        Compiler {
    21вҶ’            bytecode: Bytecode::new(),
    22вҶ’            debug_mode: false,
    23вҶ’        }
    24вҶ’    }
    25вҶ’
    26вҶ’    /// л””лІ„к·ё лӘЁл“ң нҷңм„ұнҷ”
    27вҶ’    pub fn with_debug(mut self, debug: bool) -> Self {
    28вҶ’        self.debug_mode = debug;
    29вҶ’        self
    30вҶ’    }
    31вҶ’
    32вҶ’    /// н”„лЎңк·ёлһЁ м»ҙнҢҢмқј (л©”мқё м§„мһ…м җ)
    33вҶ’    pub fn compile(&mut self, program: &Program) -> Result<(), String> {
    34вҶ’        for statement in &program.statements {
    35вҶ’            self.compile_statement(statement)?;
    36вҶ’        }
    37вҶ’        Ok(())
    38вҶ’    }
    39вҶ’
    40вҶ’    /// л¬ёмһҘ м»ҙнҢҢмқј
    41вҶ’    fn compile_statement(&mut self, stmt: &Statement) -> Result<(), String> {
    42вҶ’        match stmt {
    43вҶ’            Statement::Let { name: _, value } => {
    44вҶ’                // к°’мқ„ лЁјм Җ м»ҙнҢҢмқј (ліҖмҲҳ н• лӢ№мқҖ нӣ„мң„ мҲңм„ңлЎң)
    45вҶ’                self.compile_expression(value)?;
    46вҶ’            }
    47вҶ’
    48вҶ’            Statement::Expression(expr) => {
    49вҶ’                self.compile_expression(expr)?;
    50вҶ’            }
    51вҶ’
    52вҶ’            Statement::Return(expr) => {
    53вҶ’                self.compile_expression(expr)?;
    54вҶ’                self.emit(OpCode::OpReturnValue);
    55вҶ’            }
    56вҶ’
    57вҶ’            Statement::Block(stmts) => {
    58вҶ’                for stmt in stmts {
    59вҶ’                    self.compile_statement(stmt)?;
    60вҶ’                }
    61вҶ’            }
    62вҶ’        }
    63вҶ’        Ok(())
    64вҶ’    }
    65вҶ’
    66вҶ’    /// ============================================================================
    67вҶ’    /// [н•өмӢ¬] н‘ңнҳ„мӢқ м»ҙнҢҢмқј - нӣ„мң„ мҲңнҡҢ(Post-order)лЎң л°”мқҙнҠёмҪ”л“ң мғқм„ұ
    68вҶ’    /// ============================================================================
    69вҶ’    fn compile_expression(&mut self, expr: &Expression) -> Result<(), String> {
    70вҶ’        match expr {
    71вҶ’            // м •мҲҳ: мғҒмҲҳ н’Җм—җ м¶”к°Җн•ҳкі  OpConstant л°©м¶ң
    72вҶ’            Expression::Integer(value) => {
    73вҶ’                let idx = self.bytecode.add_constant(*value);
    74вҶ’                self.emit_with_operand(OpCode::OpConstant, idx as u16);
    75вҶ’            }
    76вҶ’
    77вҶ’            // л¶ҲлҰ¬м–ё
    78вҶ’            Expression::Boolean(true) => {
    79вҶ’                self.emit(OpCode::OpTrue);
    80вҶ’            }
    81вҶ’            Expression::Boolean(false) => {
    82вҶ’                self.emit(OpCode::OpFalse);
    83вҶ’            }
    84вҶ’
    85вҶ’            // null
    86вҶ’            Expression::Null => {
    87вҶ’                self.emit(OpCode::OpNull);
    88вҶ’            }
    89вҶ’
    90вҶ’            // м „мң„ м—°мӮ°: -x, !x
    91вҶ’            Expression::Prefix(op, right) => {
    92вҶ’                // 1. мҳӨлҘёмӘҪ лЁјм Җ м»ҙнҢҢмқј
    93вҶ’                self.compile_expression(right)?;
    94вҶ’                // 2. м—°мӮ°мһҗ л°©м¶ң
    95вҶ’                match op.as_str() {
    96вҶ’                    "-" => self.emit(OpCode::OpMinus),
    97вҶ’                    "!" => self.emit(OpCode::OpBang),
    98вҶ’                    _ => return Err(format!("Unknown prefix operator: {}", op)),
    99вҶ’                }
   100вҶ’            }
   101вҶ’
   102вҶ’            // мӨ‘мң„ м—°мӮ°: x + y, x - y л“ұ
   103вҶ’            Expression::Infix(op, left, right) => {
   104вҶ’                // 1. мҷјмӘҪ н”јм—°мӮ°мһҗ м»ҙнҢҢмқј (мҠӨнғқм—җ н‘ёмӢң)
   105вҶ’                self.compile_expression(left)?;
   106вҶ’                // 2. мҳӨлҘёмӘҪ н”јм—°мӮ°мһҗ м»ҙнҢҢмқј (мҠӨнғқм—җ н‘ёмӢң)
   107вҶ’                self.compile_expression(right)?;
   108вҶ’                // 3. м—°мӮ°мһҗ л°©м¶ң (мҠӨнғқм—җм„ң л‘җ к°’мқ„ нҢқн•ҳкі  кІ°кіј н‘ёмӢң)
   109вҶ’                match op.as_str() {
   110вҶ’                    "+" => self.emit(OpCode::OpAdd),
   111вҶ’                    "-" => self.emit(OpCode::OpSub),
   112вҶ’                    "*" => self.emit(OpCode::OpMul),
   113вҶ’                    "/" => self.emit(OpCode::OpDiv),
   114вҶ’                    "==" => self.emit(OpCode::OpEqual),
   115вҶ’                    "!=" => self.emit(OpCode::OpNotEqual),
   116вҶ’                    "<" => self.emit(OpCode::OpLessThan),
   117вҶ’                    ">=" => self.emit(OpCode::OpGreaterThanOrEqual),
   118вҶ’                    _ => return Err(format!("Unknown infix operator: {}", op)),
   119вҶ’                }
   120вҶ’            }
   121вҶ’
   122вҶ’            // if н‘ңнҳ„мӢқ - л°ұн•„л§Ғ мҷ„м„ұ
   123вҶ’            Expression::If {
   124вҶ’                condition,
   125вҶ’                consequence,
   126вҶ’                alternative,
   127вҶ’            } => {
   128вҶ’                // 1. мЎ°кұҙ м»ҙнҢҢмқј
   129вҶ’                self.compile_expression(condition)?;
   130вҶ’
   131вҶ’                // 2. м җн”„ лӘ…л №м–ҙ л°©м¶ң (лӘ©м Ғм§ҖлҠ” м•„м§Ғ лӘЁлҰ„)
   132вҶ’                let jump_not_truthy_pos = self.emit_placeholder(OpCode::OpJumpNotTruthy);
   133вҶ’
   134вҶ’                // 3. consequence лё”лЎқ м»ҙнҢҢмқј
   135вҶ’                for stmt in consequence {
   136вҶ’                    self.compile_statement(stmt)?;
   137вҶ’                }
   138вҶ’
   139вҶ’                // 4. else лё”лЎқ мІҳлҰ¬
   140вҶ’                if let Some(alt) = alternative {
   141вҶ’                    // elseк°Җ мһҲмңјл©ҙ: jumpлҘј else лҒқмңјлЎң, jump_not_truthyлҘј else мӢңмһ‘мңјлЎң л°ұн•„
   142вҶ’                    let jump_pos = self.emit_placeholder(OpCode::OpJump);
   143вҶ’                    self.fix_jump(jump_not_truthy_pos);
   144вҶ’                    for stmt in alt {
   145вҶ’                        self.compile_statement(stmt)?;
   146вҶ’                    }
   147вҶ’                    self.fix_jump(jump_pos);
   148вҶ’                } else {
   149вҶ’                    // elseк°Җ м—Ҷмңјл©ҙ: jump_not_truthyлҘј if мқҙнӣ„лЎң л°ұн•„
   150вҶ’                    self.fix_jump(jump_not_truthy_pos);
   151вҶ’                }
   152вҶ’            }
   153вҶ’
   154вҶ’            // while лЈЁн”„ - нӣ„л°© м җн”„ (мЈјмҶҢ лҜёлҰ¬ м•Ңкі  мһҲмқҢ)
   155вҶ’            Expression::While { condition, body } => {
   156вҶ’                let loop_start = self.bytecode.len() as u16;
   157вҶ’
   158вҶ’                // 1. мЎ°кұҙ м»ҙнҢҢмқј
   159вҶ’                self.compile_expression(condition)?;
   160вҶ’
   161вҶ’                // 2. кұ°м§“мқҙл©ҙ лЈЁн”„ нғҲм¶ң
   162вҶ’                let jump_not_truthy_pos = self.emit_placeholder(OpCode::OpJumpNotTruthy);
   163вҶ’
   164вҶ’                // 3. лЈЁн”„ ліёмІҙ м»ҙнҢҢмқј
   165вҶ’                for stmt in body {
   166вҶ’                    self.compile_statement(stmt)?;
   167вҶ’                }
   168вҶ’
   169вҶ’                // 4. лЈЁн”„ мӢңмһ‘мңјлЎң лӢӨмӢң м җн”„ (мЈјмҶҢ мқҙлҜё м•Ңкі  мһҲмқҢ)
   170вҶ’                self.emit_with_operand(OpCode::OpJump, loop_start);
   171вҶ’
   172вҶ’                // 5. лЈЁн”„ нғҲм¶ң мң„м№ҳлЎң л°ұн•„
   173вҶ’                self.fix_jump(jump_not_truthy_pos);
   174вҶ’            }
   175вҶ’
   176вҶ’            // н•ЁмҲҳ нҳём¶ң
   177вҶ’            Expression::Call { function, arguments } => {
   178вҶ’                // 1. н•ЁмҲҳ м»ҙнҢҢмқј
   179вҶ’                self.compile_expression(function)?;
   180вҶ’
   181вҶ’                // 2. мқёмһҗл“Ө м»ҙнҢҢмқј
   182вҶ’                for arg in arguments {
   183вҶ’                    self.compile_expression(arg)?;
   184вҶ’                }
   185вҶ’
   186вҶ’                // 3. Call лӘ…л №м–ҙ (мқёмһҗ к°ңмҲҳ м§Җм •)
   187вҶ’                self.emit_with_operand(OpCode::OpCall, arguments.len() as u16);
   188вҶ’            }
   189вҶ’
   190вҶ’            // л°°м—ҙ
   191вҶ’            Expression::Array(elements) => {
   192вҶ’                // 1. к°Ғ мҡ”мҶҢ м»ҙнҢҢмқј
   193вҶ’                for elem in elements {
   194вҶ’                    self.compile_expression(elem)?;
   195вҶ’                }
   196вҶ’                // 2. Array лӘ…л №м–ҙ (мҡ”мҶҢ к°ңмҲҳ)
   197вҶ’                self.emit_with_operand(OpCode::OpArray, elements.len() as u16);
   198вҶ’            }
   199вҶ’
   200вҶ’            // мқёлҚұмӢұ
   201вҶ’            Expression::Index(left, index) => {
   202вҶ’                // 1. мҷјмӘҪ(л°°м—ҙ/н•ҙмӢң) м»ҙнҢҢмқј
   203вҶ’                self.compile_expression(left)?;
   204вҶ’                // 2. мқёлҚұмҠӨ м»ҙнҢҢмқј
   205вҶ’                self.compile_expression(index)?;
   206вҶ’                // 3. Index лӘ…л №м–ҙ
   207вҶ’                self.emit(OpCode::OpIndex);
   208вҶ’            }
   209вҶ’
   210вҶ’            // мӢқлі„мһҗ (м¶”нӣ„ кө¬нҳ„)
   211вҶ’            Expression::Identifier(_) => {
   212вҶ’                return Err("Identifiers not yet implemented".to_string());
   213вҶ’            }
   214вҶ’        }
   215вҶ’
   216вҶ’        Ok(())
   217вҶ’    }
   218вҶ’
   219вҶ’    /// лӢЁмқј л°”мқҙнҠё лӘ…л №м–ҙ л°©м¶ң
   220вҶ’    fn emit(&mut self, op: OpCode) {
   221вҶ’        self.bytecode.add_instruction(op.as_byte());
   222вҶ’    }
   223вҶ’
   224вҶ’    /// н”јм—°мӮ°мһҗ(u16 = 2л°”мқҙнҠё)лҘј нҸ¬н•Ён•ң лӘ…л №м–ҙ л°©м¶ң
   225вҶ’    fn emit_with_operand(&mut self, op: OpCode, operand: u16) {
   226вҶ’        self.emit(op);
   227вҶ’        // u16мқ„ [high_byte, low_byte]лЎң л¶„н•ҙ
   228вҶ’        let high = (operand >> 8) as u8;
   229вҶ’        let low = (operand & 0xFF) as u8;
   230вҶ’        self.bytecode.add_instruction(high);
   231вҶ’        self.bytecode.add_instruction(low);
   232вҶ’    }
   233вҶ’
   234вҶ’    /// м җн”„ лӘ…л №м–ҙлҘј л°©м¶ңн•ҳм§Җл§Ң лӘ©м Ғм§ҖлҠ” м•„м§Ғ лӘЁлҰ„ (лӮҳмӨ‘м—җ мҲҳм •) - 3л°”мқҙнҠё
   235вҶ’    fn emit_placeholder(&mut self, op: OpCode) -> usize {
   236вҶ’        let pos = self.bytecode.len();
   237вҶ’        self.bytecode.add_instruction(op.as_byte());      // OpJumpNotTruthy
   238вҶ’        self.bytecode.add_instruction(0x00);              // operand high byte
   239вҶ’        self.bytecode.add_instruction(0x00);              // operand low byte
   240вҶ’        pos
   241вҶ’    }
   242вҶ’
   243вҶ’    /// мқҙм „м—җ л°©м¶ңн•ң м җн”„мқҳ лӘ©м Ғм§ҖлҘј мҲҳм • (л°ұн•„л§Ғ)
   244вҶ’    fn change_operand(&mut self, pos: usize, operand: u16) {
   245вҶ’        let bytes = operand.to_be_bytes();
   246вҶ’        self.bytecode.instructions[pos + 1] = bytes[0];
   247вҶ’        self.bytecode.instructions[pos + 2] = bytes[1];
   248вҶ’
   249вҶ’        if self.debug_mode {
   250вҶ’            eprintln!(
   251вҶ’                "[BACKFILL] @{}: operand=0x{:04x} ({})",
   252вҶ’                pos, operand, operand
   253вҶ’            );
   254вҶ’        }
   255вҶ’    }
   256вҶ’
   257вҶ’    /// fix_jumpлҠ” change_operandм—җ мң„мһ„
   258вҶ’    fn fix_jump(&mut self, pos: usize) {
   259вҶ’        let target = self.bytecode.len() as u16;
   260вҶ’        self.change_operand(pos, target);
   261вҶ’    }
   262вҶ’
   263вҶ’    /// м»ҙнҢҢмқјлҗң л°”мқҙнҠёмҪ”л“ң л°ҳнҷҳ
   264вҶ’    pub fn bytecode(&self) -> Bytecode {
   265вҶ’        self.bytecode.clone()
   266вҶ’    }
   267вҶ’}
   268вҶ’
   269вҶ’impl Default for Compiler {
   270вҶ’    fn default() -> Self {
   271вҶ’        Self::new()
   272вҶ’    }
   273вҶ’}
