     6вҶ’/// м»ҙнҢҢмқјлҗң л°”мқҙнҠёмҪ”л“ң
     7вҶ’#[derive(Debug, Clone)]
     8вҶ’pub struct Bytecode {
     9вҶ’    /// лӘ…л №м–ҙ л°”мқҙнҠё мҠӨнҠёлҰј
    10вҶ’    pub instructions: Vec<u8>,
    11вҶ’
    12вҶ’    /// мғҒмҲҳ н’Җ (м •мҲҳ)
    13вҶ’    pub constants: Vec<i64>,
    14вҶ’}
    15вҶ’
    16вҶ’impl Bytecode {
    17вҶ’    /// мғҲлЎңмҡҙ л°”мқҙнҠёмҪ”л“ң мғқм„ұ
    18вҶ’    pub fn new() -> Self {
    19вҶ’        Bytecode {
    20вҶ’            instructions: Vec::new(),
    21вҶ’            constants: Vec::new(),
    22вҶ’        }
    23вҶ’    }
    24вҶ’
    25вҶ’    /// лӘ…л №м–ҙ кёёмқҙ
    26вҶ’    pub fn len(&self) -> usize {
    27вҶ’        self.instructions.len()
    28вҶ’    }
    29вҶ’
    30вҶ’    /// мғҒмҲҳ м¶”к°Җ
    31вҶ’    pub fn add_constant(&mut self, value: i64) -> usize {
    32вҶ’        self.constants.push(value);
